#include <bits/stdc++.h>
#define R register
using namespace std;

const int N=5e5+5;

int T,n,m;
long long k;

long long a[N];
long long srt[N];
long long tmp[N];

bool check(R int l,R int mid,R int r){
    if(r>n) return 0;

    for(R int i=mid+1;i<=r;i++)
        srt[i]=a[i];

    sort(srt+mid+1,srt+r+1);

    R int p1=l,p2=mid+1,p=l;

    while(p1<=mid&&p2<=r){
        if(srt[p1]<srt[p2])
            tmp[p++]=srt[p1++];
        else
            tmp[p++]=srt[p2++];
    }

    while(p1<=mid)
        tmp[p++]=srt[p1++];

    while(p2<=r)
        tmp[p++]=srt[p2++];

    long long sum=0;

    for(R int i=l,j=r,cnt=0;i<j&&cnt<m;i++,j--,cnt++){
        long long d=tmp[j]-tmp[i];
        sum+=d*d;
        if(sum>k)
            return 0;
    }

    for(R int i=l;i<=r;i++)
        srt[i]=tmp[i];

    return 1;
}

int main(){
    scanf("%d",&T);

    while(T--){

        scanf("%d%d%lld",&n,&m,&k);

        for(R int i=1;i<=n;i++){
            scanf("%lld",&a[i]);
            srt[i]=a[i];
        }

        R int ans=0;

        for(R int l=1,r=0;l<=n;ans++){

            R int p=1;

            while(check(l,r,r+p)){
                r+=p;
                p<<=1;
            }

            p>>=1;

            while(p){
                if(check(l,r,r+p))
                    r+=p;
                p>>=1;
            }

            l=r+1;
        }

        printf("%d\n",ans);
    }

    return 0;
}
